import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { motion } from 'framer-motion';
import { FaArrowLeft, FaEnvelope, FaLock, FaBuilding, FaUserShield, FaChartPie, FaUsersCog } from 'react-icons/fa';
import './Login.css';

function Login() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const { login } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        try {
            const user = await login(email, password);

            // Redirect based on role
            if (user.role === 'super_admin') {
                navigate('/dashboard');
            } else if (user.role === 'supervisor') {
                navigate('/supervisor-dashboard');
            }
        } catch (err) {
            setError(err.response?.data?.message || 'Login failed. Please check your credentials.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="login-container">
            <motion.button
                className="back-to-home"
                onClick={() => navigate('/')}
                whileHover={{ x: -5 }}
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
            >
                <FaArrowLeft /> Back to Home
            </motion.button>

            <div className="login-wrapper">
                <motion.div
                    className="login-left"
                    initial={{ opacity: 0, x: -50 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ duration: 0.8 }}
                >
                    <div className="login-branding">
                        <motion.div
                            className="brand-icon"
                            animate={{ rotateY: 360 }}
                            transition={{ duration: 2, repeat: Infinity, repeatDelay: 5 }}
                        >
                            🏗️
                        </motion.div>
                        <h1>BuildPro CMS</h1>
                        <p className="branding-text">
                            The ultimate construction management system. Streamline your operations, manage
                            workforce, and track progress with precision.
                        </p>

                        <div className="features-list">
                            <motion.div
                                className="feature-item"
                                initial={{ opacity: 0, x: -20 }}
                                animate={{ opacity: 1, x: 0 }}
                                transition={{ delay: 0.3 }}
                            >
                                <div className="feature-icon-wrapper"><FaBuilding /></div>
                                <span>Multi-company Management</span>
                            </motion.div>
                            <motion.div
                                className="feature-item"
                                initial={{ opacity: 0, x: -20 }}
                                animate={{ opacity: 1, x: 0 }}
                                transition={{ delay: 0.4 }}
                            >
                                <div className="feature-icon-wrapper"><FaUserShield /></div>
                                <span>Secure Role-based Access</span>
                            </motion.div>
                            <motion.div
                                className="feature-item"
                                initial={{ opacity: 0, x: -20 }}
                                animate={{ opacity: 1, x: 0 }}
                                transition={{ delay: 0.5 }}
                            >
                                <div className="feature-icon-wrapper"><FaChartPie /></div>
                                <span>Advanced Analytics</span>
                            </motion.div>
                            <motion.div
                                className="feature-item"
                                initial={{ opacity: 0, x: -20 }}
                                animate={{ opacity: 1, x: 0 }}
                                transition={{ delay: 0.6 }}
                            >
                                <div className="feature-icon-wrapper"><FaUsersCog /></div>
                                <span>Team Coordination</span>
                            </motion.div>
                        </div>
                    </div>
                </motion.div>

                <motion.div
                    className="login-right"
                    initial={{ opacity: 0, x: 50 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ duration: 0.8 }}
                >
                    <div className="login-card">
                        <div className="login-header">
                            <h2>Welcome Back</h2>
                            <p>Please enter your details to sign in</p>
                        </div>

                        {error && (
                            <motion.div
                                className="error-message"
                                initial={{ opacity: 0, y: -10 }}
                                animate={{ opacity: 1, y: 0 }}
                            >
                                {error}
                            </motion.div>
                        )}

                        <form onSubmit={handleSubmit} className="modern-form">
                            <div className="form-group">
                                <label htmlFor="email">Email Address</label>
                                <div className="input-wrapper">
                                    <FaEnvelope className="input-icon" />
                                    <input
                                        type="email"
                                        id="email"
                                        value={email}
                                        onChange={(e) => setEmail(e.target.value)}
                                        placeholder="name@company.com"
                                        required
                                    />
                                </div>
                            </div>

                            <div className="form-group">
                                <label htmlFor="password">Password</label>
                                <div className="input-wrapper">
                                    <FaLock className="input-icon" />
                                    <input
                                        type="password"
                                        id="password"
                                        value={password}
                                        onChange={(e) => setPassword(e.target.value)}
                                        placeholder="••••••••"
                                        required
                                    />
                                </div>
                            </div>

                            <button type="submit" className="login-btn" disabled={loading}>
                                {loading ? (
                                    <span className="loader"></span>
                                ) : (
                                    'Sign In'
                                )}
                            </button>
                        </form>

                        <div className="test-credentials">
                            <p><strong>Test Credentials:</strong></p>
                            <div className="credential-row">
                                <span>Admin:</span>
                                <code>admin@admin.com / admin123</code>
                            </div>
                            <div className="credential-row">
                                <span>Supervisor:</span>
                                <code>test@example.com / password</code>
                            </div>
                        </div>
                    </div>
                </motion.div>
            </div>
        </div>
    );
}

export default Login;
